import{_ as a,c as e,o as i,a1 as o}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Diffビュー: 複数の視点で変更をレビュー | Plannotator","description":"Plannotatorのコードレビューでdiffタイプを切り替える方法を学びます。ドロップダウンメニューからuncommitted、staged、last commit、branchビューを選択し、複数の視点からコード変更をレビューできます。","frontmatter":{"title":"Diffビュー: 複数の視点で変更をレビュー | Plannotator","sidebarTitle":"5種類のDiffビュー切り替え","subtitle":"Diffビュー: 複数の視点で変更をレビュー","description":"Plannotatorのコードレビューでdiffタイプを切り替える方法を学びます。ドロップダウンメニューからuncommitted、staged、last commit、branchビューを選択し、複数の視点からコード変更をレビューできます。","tags":["コードレビュー","Git","Diff","チュートリアル"],"prerequisite":["code-review-basics"],"order":6},"headers":[],"relativePath":"ja/backnotprop/plannotator/platforms/code-review-diff-types/index.md","filePath":"ja/backnotprop/plannotator/platforms/code-review-diff-types/index.md"}'),d={name:"ja/backnotprop/plannotator/platforms/code-review-diff-types/index.md"};function r(s,t,n,l,p,c){return i(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="diffビューの切り替え" tabindex="-1">Diffビューの切り替え <a class="header-anchor" href="#diffビューの切り替え" aria-label="Permalink to &quot;Diffビューの切り替え&quot;">​</a></h1><h2 id="この章で学べること" tabindex="-1">この章で学べること <a class="header-anchor" href="#この章で学べること" aria-label="Permalink to &quot;この章で学べること&quot;">​</a></h2><p>コードレビュー時に、以下のことができるようになります：</p><ul><li>ドロップダウンメニューで5種類のdiffビューを素早く切り替える</li><li>各ビューが表示するコード変更の範囲を理解する</li><li>レビューの目的に応じて適切なdiffタイプを選択する</li><li>間違ったビューを選択して重要な変更を見落とすことを防ぐ</li></ul><h2 id="現在の課題" tabindex="-1">現在の課題 <a class="header-anchor" href="#現在の課題" aria-label="Permalink to &quot;現在の課題&quot;">​</a></h2><p><strong>レビュー時にワーキングディレクトリだけを見て、ステージ済みファイルを見落とす</strong>：</p><p><code>/plannotator-review</code>コマンドを実行し、いくつかのコード変更を確認してアノテーションを追加しました。しかしコミット後、すでに<code>git add</code>でステージングエリアに追加されていたファイルがレビューから漏れていたことに気づきました——これらのファイルはdiffに表示されていなかったのです。</p><p><strong>現在のブランチとmainブランチの全体的な差分を確認したい</strong>：</p><p>featureブランチで数週間開発を続けてきて、全体でどのような変更があったか確認したいのですが、デフォルトの「未コミット変更」ビューでは最近数日の修正しか表示されません。</p><p><strong>特定の2つのコミット間の差分を比較したい</strong>：</p><p>あるバグ修正が正しく行われたか確認するため、修正前後のコードを比較したいのですが、Plannotatorで過去のコミットのdiffを表示する方法がわかりません。</p><h2 id="こんなときに使う" tabindex="-1">こんなときに使う <a class="header-anchor" href="#こんなときに使う" aria-label="Permalink to &quot;こんなときに使う&quot;">​</a></h2><ul><li><strong>包括的なレビュー時</strong>：ワーキングディレクトリとステージングエリアの変更を同時に確認</li><li><strong>ブランチマージ前</strong>：現在のブランチのmain/masterに対するすべての変更を確認</li><li><strong>ロールバック確認時</strong>：最後のコミットでどのファイルが変更されたか確認</li><li><strong>チーム協業時</strong>：同僚がステージしたがまだコミットしていないコードを確認</li></ul><h2 id="コアコンセプト" tabindex="-1">コアコンセプト <a class="header-anchor" href="#コアコンセプト" aria-label="Permalink to &quot;コアコンセプト&quot;">​</a></h2><p>Git diffコマンドには多くのバリエーションがあり、それぞれ異なるコード範囲を表示します。Plannotatorはこれらのバリエーションを1つのドロップダウンメニューにまとめ、複雑なgitコマンドを覚える必要をなくしました。</p><div class="info custom-block"><p class="custom-block-title">Git Diffタイプ早見表</p><table tabindex="0"><thead><tr><th>diffタイプ</th><th>表示範囲</th><th>典型的な使用シナリオ</th></tr></thead><tbody><tr><td>Uncommitted changes</td><td>ワーキングディレクトリ + ステージングエリア</td><td>今回の開発のすべての修正をレビュー</td></tr><tr><td>Staged changes</td><td>ステージングエリアのみ</td><td>コミット前にステージ済み内容を確認</td></tr><tr><td>Unstaged changes</td><td>ワーキングディレクトリのみ</td><td>まだ<code>git add</code>していない修正を確認</td></tr><tr><td>Last commit</td><td>直近のコミット</td><td>ロールバックや直前のコミットの確認</td></tr><tr><td>vs main</td><td>現在のブランチ vs デフォルトブランチ</td><td>ブランチマージ前の包括的チェック</td></tr></tbody></table></div><p>ドロップダウンメニューのオプションはGitの状態に応じて動的に変化します：</p><ul><li>現在デフォルトブランチにいない場合、「vs main」オプションが表示される</li><li>ステージ済みファイルがない場合、Stagedビューは「No staged changes」と表示</li></ul><h2 id="ステップバイステップ" tabindex="-1">ステップバイステップ <a class="header-anchor" href="#ステップバイステップ" aria-label="Permalink to &quot;ステップバイステップ&quot;">​</a></h2><h3 id="ステップ1-コードレビューを起動" tabindex="-1">ステップ1：コードレビューを起動 <a class="header-anchor" href="#ステップ1-コードレビューを起動" aria-label="Permalink to &quot;ステップ1：コードレビューを起動&quot;">​</a></h3><p><strong>なぜ</strong></p><p>まずPlannotatorのコードレビューインターフェースを開く必要があります。</p><p><strong>操作</strong></p><p>ターミナルで実行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plannotator-review</span></span></code></pre></div><p><strong>期待される結果</strong></p><p>ブラウザでコードレビューページが開き、左側のファイルツリーの上部に現在のdiffタイプを表示するドロップダウンメニュー（通常は「Uncommitted changes」）があります。</p><h3 id="ステップ2-stagedビューに切り替え" tabindex="-1">ステップ2：Stagedビューに切り替え <a class="header-anchor" href="#ステップ2-stagedビューに切り替え" aria-label="Permalink to &quot;ステップ2：Stagedビューに切り替え&quot;">​</a></h3><p><strong>なぜ</strong></p><p>すでに<code>git add</code>したがまだコミットしていないファイルを確認します。</p><p><strong>操作</strong></p><ol><li>左側のファイルツリー上部のドロップダウンメニューをクリック</li><li>「Staged changes」を選択</li></ol><p><strong>期待される結果</strong></p><ul><li>ステージ済みファイルがある場合、ファイルツリーにそれらのファイルが表示される</li><li>ステージ済みファイルがない場合、メインエリアに「No staged changes. Stage some files with git add.」と表示される</li></ul><h3 id="ステップ3-last-commitビューに切り替え" tabindex="-1">ステップ3：Last Commitビューに切り替え <a class="header-anchor" href="#ステップ3-last-commitビューに切り替え" aria-label="Permalink to &quot;ステップ3：Last Commitビューに切り替え&quot;">​</a></h3><p><strong>なぜ</strong></p><p>直前にコミットしたコードをレビューし、問題がないか確認します。</p><p><strong>操作</strong></p><ol><li>再度ドロップダウンメニューを開く</li><li>「Last commit」を選択</li></ol><p><strong>期待される結果</strong></p><ul><li>直近のコミットで変更されたすべてのファイルが表示される</li><li>diff内容は<code>HEAD~1..HEAD</code>の差分</li></ul><h3 id="ステップ4-vs-mainビューに切り替え-利用可能な場合" tabindex="-1">ステップ4：vs mainビューに切り替え（利用可能な場合） <a class="header-anchor" href="#ステップ4-vs-mainビューに切り替え-利用可能な場合" aria-label="Permalink to &quot;ステップ4：vs mainビューに切り替え（利用可能な場合）&quot;">​</a></h3><p><strong>なぜ</strong></p><p>現在のブランチのデフォルトブランチに対するすべての変更を確認します。</p><p><strong>操作</strong></p><ol><li>ドロップダウンメニューに「vs main」または「vs master」オプションがあるか確認</li><li>ある場合、それを選択</li></ol><p><strong>期待される結果</strong></p><ul><li>ファイルツリーに現在のブランチとデフォルトブランチ間のすべての差分ファイルが表示される</li><li>diff内容は<code>main..HEAD</code>の完全な変更</li></ul><div class="tip custom-block"><p class="custom-block-title">現在のブランチを確認</p><p>「vs main」オプションが表示されない場合、デフォルトブランチにいることを意味します。以下のコマンドで現在のブランチを確認できます：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rev-parse</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --abbrev-ref</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> HEAD</span></span></code></pre></div><p>featureブランチに切り替えてから再試行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checkout</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature-branch</span></span></code></pre></div></div><h2 id="チェックポイント-✅" tabindex="-1">チェックポイント ✅ <a class="header-anchor" href="#チェックポイント-✅" aria-label="Permalink to &quot;チェックポイント ✅&quot;">​</a></h2><p>以下を習得できたか確認してください：</p><ul><li>[ ] diffタイプのドロップダウンメニューを見つけて開くことができる</li><li>[ ] 「Uncommitted」「Staged」「Last commit」の違いを理解している</li><li>[ ] 「vs main」オプションがいつ表示されるか識別できる</li><li>[ ] どのシナリオでどのdiffタイプを使うべきか理解している</li></ul><h2 id="よくあるトラブル" tabindex="-1">よくあるトラブル <a class="header-anchor" href="#よくあるトラブル" aria-label="Permalink to &quot;よくあるトラブル&quot;">​</a></h2><h3 id="トラブル1-レビュー時にuncommittedだけを見て、stagedファイルを見落とす" tabindex="-1">トラブル1：レビュー時にUncommittedだけを見て、Stagedファイルを見落とす <a class="header-anchor" href="#トラブル1-レビュー時にuncommittedだけを見て、stagedファイルを見落とす" aria-label="Permalink to &quot;トラブル1：レビュー時にUncommittedだけを見て、Stagedファイルを見落とす&quot;">​</a></h3><p><strong>症状</strong></p><p>コミット後、レビューでいくつかのステージ済みファイルが漏れていたことに気づく。</p><p><strong>原因</strong></p><p>Uncommittedビューはワーキングディレクトリとステージングエリアのすべての変更（<code>git diff HEAD</code>）を表示し、ステージ済みファイルも含まれます。</p><p><strong>解決方法</strong></p><p>レビュー前にまずStagedビューに切り替えて確認するか、Uncommittedビュー（ステージングエリアを含む）を使用します。</p><h3 id="トラブル2-ブランチマージ前にmainと比較しない" tabindex="-1">トラブル2：ブランチマージ前にmainと比較しない <a class="header-anchor" href="#トラブル2-ブランチマージ前にmainと比較しない" aria-label="Permalink to &quot;トラブル2：ブランチマージ前にmainと比較しない&quot;">​</a></h3><p><strong>症状</strong></p><p>mainにマージ後、関係のない変更が含まれていたことに気づく。</p><p><strong>原因</strong></p><p>最近数日のコミットだけを見て、ブランチ全体のmainに対する差分を比較していなかった。</p><p><strong>解決方法</strong></p><p>マージ前に「vs main」ビューで包括的にチェックします。</p><h3 id="トラブル3-ビュー切り替えでアノテーションが消えると思い込む" tabindex="-1">トラブル3：ビュー切り替えでアノテーションが消えると思い込む <a class="header-anchor" href="#トラブル3-ビュー切り替えでアノテーションが消えると思い込む" aria-label="Permalink to &quot;トラブル3：ビュー切り替えでアノテーションが消えると思い込む&quot;">​</a></h3><p><strong>症状</strong></p><p>diffタイプを切り替えることを躊躇し、以前追加したアノテーションが消えることを心配する。</p><p><strong>原因</strong></p><p>切り替えメカニズムの誤解。</p><p><strong>実際の動作</strong></p><p>diffタイプを切り替えても、Plannotatorは以前のアノテーションを保持します——それらは引き続き適用される可能性があり、関係のないアノテーションは手動で削除できます。</p><h2 id="この章のまとめ" tabindex="-1">この章のまとめ <a class="header-anchor" href="#この章のまとめ" aria-label="Permalink to &quot;この章のまとめ&quot;">​</a></h2><p>Plannotatorがサポートする5種類のdiffタイプ：</p><table tabindex="0"><thead><tr><th>タイプ</th><th>Gitコマンド</th><th>シナリオ</th></tr></thead><tbody><tr><td>Uncommitted</td><td><code>git diff HEAD</code></td><td>今回の開発のすべての修正をレビュー</td></tr><tr><td>Staged</td><td><code>git diff --staged</code></td><td>コミット前にステージングエリアを確認</td></tr><tr><td>Unstaged</td><td><code>git diff</code></td><td>ワーキングディレクトリの修正を確認</td></tr><tr><td>Last commit</td><td><code>git diff HEAD~1..HEAD</code></td><td>ロールバックや直近のコミットを確認</td></tr><tr><td>vs main</td><td><code>git diff main..HEAD</code></td><td>ブランチマージ前の包括的チェック</td></tr></tbody></table><p>ビューを切り替えてもアノテーションは失われません。異なる視点から同じアノテーションや新しいアノテーションを確認できます。</p><h2 id="次の章の予告" tabindex="-1">次の章の予告 <a class="header-anchor" href="#次の章の予告" aria-label="Permalink to &quot;次の章の予告&quot;">​</a></h2><blockquote><p>次の章では**<a href="./../../advanced/url-sharing/">URL共有</a>**を学びます。</p><p>学べる内容：</p><ul><li>レビュー内容をURLに圧縮して同僚と共有する方法</li><li>受信者が共有されたレビューリンクを開く方法</li><li>共有モードでの制限と注意事項</li></ul></blockquote><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を表示</strong></summary><blockquote><p>更新日：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>Diffタイプ定義</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L10-L15" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>10-15</td></tr><tr><td>Gitコンテキスト取得</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L79-L96" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>79-96</td></tr><tr><td>Git Diff実行</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L101-L147" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>101-147</td></tr><tr><td>Diff切り替え処理</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/review-editor/App.tsx#L300-L331" target="_blank" rel="noreferrer"><code>packages/review-editor/App.tsx</code></a></td><td>300-331</td></tr><tr><td>ファイルツリーのDiffオプション描画</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/review-editor/components/FileTree.tsx" target="_blank" rel="noreferrer"><code>packages/review-editor/components/FileTree.tsx</code></a></td><td>-</td></tr></tbody></table><p><strong>主要な型</strong>：</p><ul><li><code>DiffType</code>: <code>&#39;uncommitted&#39; | &#39;staged&#39; | &#39;unstaged&#39; | &#39;last-commit&#39; | &#39;branch&#39;</code></li></ul><p><strong>主要な関数</strong>：</p><ul><li><code>getGitContext()</code>: 現在のブランチ、デフォルトブランチ、利用可能なdiffオプションを取得</li><li><code>runGitDiff(diffType, defaultBranch)</code>: diffタイプに応じて対応するgitコマンドを実行</li></ul><p><strong>主要なAPI</strong>：</p><ul><li><code>POST /api/diff/switch</code>: diffタイプを切り替え、新しいdiffデータを返す</li></ul></details>',83)])])}const f=a(d,[["render",r]]);export{g as __pageData,f as default};
